using System.Net.Http.Json;
using System.Text.Json;
using System.Text.Json.Serialization;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap the JSONPlaceholder REST API via HttpClient.
/// Uses constructor injection — the SDK resolves HttpClient and ILogger
/// from DI automatically; they never appear in the tool schema.
/// </summary>
[McpServerToolType]
public class RestApiTools(HttpClient httpClient, ILogger<RestApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        WriteIndented = true,
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        DefaultIgnoreCondition = JsonIgnoreCondition.WhenWritingNull
    };

    [McpServerTool, Description("Get a post by its numeric ID from the REST API.")]
    public async Task<string> GetPost(
        [Description("The numeric post ID (1-100)")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {PostId}", postId);
        var post = await httpClient.GetFromJsonAsync<JsonElement>(
            $"posts/{postId}", cancellationToken);
        return JsonSerializer.Serialize(post, JsonOptions);
    }

    [McpServerTool, Description("List posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter posts by this user ID (optional)")] int? userId = null,
        [Description("Max number of posts to return (default 10)")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"posts?userId={userId.Value}" : "posts";
        logger.LogInformation("Listing posts: url={Url}, limit={Limit}", url, limit);

        var posts = await httpClient.GetFromJsonAsync<JsonElement[]>(url, cancellationToken)
                    ?? [];
        var result = posts.Take(limit);
        return JsonSerializer.Serialize(result, JsonOptions);
    }

    [McpServerTool, Description("Search for users by name. Returns matching user profiles.")]
    public async Task<string> SearchUsers(
        [Description("Partial name to search for (case-insensitive)")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching users: query={Query}", query);
        var users = await httpClient.GetFromJsonAsync<JsonElement[]>(
            "users", cancellationToken) ?? [];

        var matches = users.Where(u =>
            u.GetProperty("name").GetString()?.Contains(query, StringComparison.OrdinalIgnoreCase) == true);
        return JsonSerializer.Serialize(matches, JsonOptions);
    }

    [McpServerTool, Description("Get all comments for a specific post.")]
    public async Task<string> GetComments(
        [Description("The post ID to retrieve comments for")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching comments for post {PostId}", postId);
        var comments = await httpClient.GetFromJsonAsync<JsonElement[]>(
            $"posts/{postId}/comments", cancellationToken) ?? [];
        return JsonSerializer.Serialize(comments, JsonOptions);
    }

    [McpServerTool(Destructive = false, ReadOnly = true),
     Description("Create a new post (simulated). The API accepts the data but does not persist it.")]
    public async Task<string> CreatePost(
        [Description("Title of the new post")] string title,
        [Description("Body content of the post")] string body,
        [Description("User ID of the author")] int authorUserId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating post by user {UserId}", authorUserId);
        var payload = new { title, body, userId = authorUserId };
        var response = await httpClient.PostAsJsonAsync("posts", payload, cancellationToken);
        response.EnsureSuccessStatusCode();

        var created = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(created, JsonOptions);
    }
}

